+export type SessionRow = {
+  key: string;
+  channel?: string;
+  lastChannel?: string;
+  lastTo?: string;
+  lastAccountId?: string;
+  lastThreadId?: string | number;
+  deliveryContext?: {
+    channel?: string;
+    to?: string;
+    accountId?: string;
+    threadId?: string | number;
+  };
+  origin?: {
+    provider?: string;
+    accountId?: string;
+    threadId?: string | number;
+  };
+  label?: string;
+  displayName?: string;
+  derivedTitle?: string;
+  lastMessagePreview?: string;
+  updatedAt?: number | null;
+};
+
+export type SessionListResult = {
+  sessions?: SessionRow[];
+};
+
+export type ChatHistoryResult = {
+  messages?: Array<{ id?: string; role?: string; content?: unknown; [key: string]: unknown }>;
+};
+
+export type SessionMessagePayload = {
+  sessionKey?: string;
+  messageId?: string;
+  messageSeq?: number;
+  message?: { role?: string; content?: unknown; [key: string]: unknown };
+  lastChannel?: string;
+  lastTo?: string;
+  lastAccountId?: string;
+  lastThreadId?: string | number;
+  [key: string]: unknown;
+};
+
+export type ApprovalKind = "exec" | "plugin";
+export type ApprovalDecision = "allow-once" | "allow-always" | "deny";
+
+export type PendingApproval = {
+  kind: ApprovalKind;
+  id: string;
+  request?: Record<string, unknown>;
+  createdAtMs?: number;
+  expiresAtMs?: number;
+};
+
+export type QueueEvent =
+  | {
+      cursor: number;
+      type: "message";
+      sessionKey: string;
+      conversation?: ConversationDescriptor;
+      messageId?: string;
+      messageSeq?: number;
+      role?: string;
+      text?: string;
+      raw: SessionMessagePayload;
+    }
+  | {
+      cursor: number;
+      type: "claude_permission_request";
+      requestId: string;
+      toolName: string;
+      description: string;
+      inputPreview: string;
+    }
+  | {
+      cursor: number;
+      type: "exec_approval_requested" | "exec_approval_resolved";
+      raw: Record<string, unknown>;
+    }
+  | {
+      cursor: number;
+      type: "plugin_approval_requested" | "plugin_approval_resolved";
+      raw: Record<string, unknown>;
+    };
+
+export type ClaudePermissionRequest = {
+  toolName: string;
+  description: string;
